import axios from 'axios';
import React, { useEffect, useState } from 'react';
import { Select, Option } from "@material-tailwind/react";

export default function AddGroup() {
	const [groups, setGroups] = useState([])
  useEffect(()=>{
    axios.post("http://localhost:5555/groups")
    .then(groups=>setGroups(groups.data))
    .catch(err=>console.log(err))
  },[])

  return (
    <div className="bg-white px-4 pt-3 pb-4 rounded-sm border border-gray-200 flex-1">
            <div className="flex justify-end">
      <button size="sm" class="bg-blue-500 text-white px-4 py-2 rounded-md justify-end">
      Add
      </button>
      </div>
      <strong className="text-gray-700 font-medium">Groups</strong>
      <div className="border-x border-gray-200 rounded-sm mt-3">
        <table className="w-full text-gray-700">
          <thead>
            <tr>
              <th>Специальност</th>
              <th>Курс</th>
              <th>Группа</th>

            </tr>
          </thead>
          <tbody>
            <div className="w-72">
              <Select>
                <Option>Material Tailwind HTML</Option>
              </Select>
            </div>
          </tbody>
        </table>
      </div>
    </div>
  );
};
